from jinja2.loaders import validate_template_path, split_template_path
from jinja2.exceptions import TemplateNotFound

cases = ["", None, "a\x00b", "/etc/passwd", "\\windows\\path", "C:\\foo", "d:foo", "a\x01b", "a\tb\nc\rd", "normal/path.html", "../evil"]
for c in cases:
    try:
        validate_template_path(c)
        print(repr(c), "-> OK (no raise)")
    except TemplateNotFound:
        print(repr(c), "-> TemplateNotFound")
    except Exception as e:
        print(repr(c), "-> OTHER ERROR", e)

# split_template_path should still catch ..
try:
    split_template_path("../evil")
except TemplateNotFound:
    print("split_template_path ../evil -> TemplateNotFound (expected)")
